class Solution:
    def minOperations(self, nums1: List[int], nums2: List[int], k: int) -> int:
        total_diff = 0
        operations = 0
        for n1, n2 in zip(nums1, nums2):
            diff = n1 - n2
            if diff == 0:
                continue
            if k == 0:
                return -1
            if diff % k != 0:
                return -1
            total_diff += diff
            operations += abs(diff) // k
        return operations if total_diff == 0 else -1
