import heapq

class Solution:
    def maximumMinutes(self, grid: List[List[int]]) -> int:
        m, n = len(grid), len(grid[0])

        # Precompute the time when fire reaches each cell
        fire_time = [[float('inf')] * n for _ in range(m)]
        directions = [(-1, 0), (1, 0), (0, -1), (0, 1)]

        # Initialize fire spread from initial fire cells
        fire_queue = []
        for i in range(m):
            for j in range(n):
                if grid[i][j] == 1:
                    fire_time[i][j] = 0
                    heapq.heappush(fire_queue, (0, i, j))

        # Spread fire using Dijkstra's algorithm
        while fire_queue:
            time, x, y = heapq.heappop(fire_queue)
            if time > fire_time[x][y]:
                continue
            for dx, dy in directions:
                nx, ny = x + dx, y + dy
                if 0 <= nx < m and 0 <= ny < n and grid[nx][ny] != 2 and fire_time[nx][ny] > time + 1:
                    fire_time[nx][ny] = time + 1
                    heapq.heappush(fire_queue, (time + 1, nx, ny))

        # BFS to find the maximum time you can wait
        def can_reach(wait_time):
            visited = [[False] * n for _ in range(m)]
            queue = [(0, 0, wait_time)]  # (time, x, y)
            visited[0][0] = True

            while queue:
                time, x, y = heapq.heappop(queue)
                if x == m - 1 and y == n - 1:
                    return True
                for dx, dy in directions:
                    nx, ny = x + dx, y + dy
                    if 0 <= nx < m and 0 <= ny < n and not visited[nx][ny] and grid[nx][ny] != 2:
                        # Check if the cell is not on fire at (time + 1)
                        if fire_time[nx][ny] > time + 1:
                            visited[nx][ny] = True
                            heapq.heappush(queue, (time + 1, nx, ny))
                        # Special case for the safehouse
                        elif nx == m - 1 and ny == n - 1 and fire_time[nx][ny] == time + 1:
                            return True
            return False

        # Binary search for the maximum wait time
        low, high = 0, 10**9
        result = -1
        while low <= high:
            mid = (low + high) // 2
            if can_reach(mid):
                result = mid
                low = mid + 1
            else:
                high = mid - 1

        # Check if the safehouse is reachable without any wait time
        if can_reach(0):
            if all(fire_time[i][j] > 10**9 for i in range(m) for j in range(n)):
                return 10**9
            else:
                return result if result != -1 else 0
        else:
            return -1
