class Solution:
    def minSkips(self, dist: List[int], speed: int, hoursBefore: int) -> int:
        n = len(dist)
        dp = [[float('inf')] * (n + 1) for _ in range(n + 1)]
        dp[0][0] = 0

        for i in range(1, n + 1):
            for skips in range(i + 1):
                time = 0
                for j in range(i):
                    time += dist[j] / speed
                    if j < i - 1:
                        time = math.ceil(time) if skips <= j else time

                if skips <= i - 1:
                    dp[i][skips] = time

        for skips in range(n + 1):
            if dp[n][skips] <= hoursBefore:
                return skips

        return -1
