from typing import List

class Solution:
    def maximumSubarraySum(self, nums: List[int], k: int) -> int:
        max_sum = 0
        current_sum = 0
        frequency = {}

        for i in range(len(nums)):
            # Add current element to the window
            current_sum += nums[i]
            frequency[nums[i]] = frequency.get(nums[i], 0) + 1

            # If the window size exceeds k, remove the element going out of the window
            if i >= k:
                out_element = nums[i - k]
                frequency[out_element] -= 1
                if frequency[out_element] == 0:
                    del frequency[out_element]
                current_sum -= out_element

            # Check if the window size is exactly k and all elements are distinct
            if i >= k - 1:
                if len(frequency) == k:
                    if current_sum > max_sum:
                        max_sum = current_sum

        return max_sum

