class Solution:
    def minLengthAfterRemovals(self, nums: List[int]) -> int:
        # Count the frequency of the most common element
        count = {}
        for num in nums:
            count[num] = count.get(num, 0) + 1
        max_count = max(count.values())

        # The maximum possible pairs we can form is limited by the sum of the frequencies of the other elements
        # If the most frequent element's count is more than half the array length,
        # then the remaining elements can't pair with all of them
        n = len(nums)
        if max_count > n - max_count:
            # The minimum length is 2*max_count - n
            return 2 * max_count - n
        else:
            # All elements can be paired, so the minimum length is n % 2
            return n % 2
