from typing import List

class Solution:
    def findPeakGrid(self, mat: List[List[int]]) -> List[int]:
        m, n = len(mat), len(mat[0])

        # Binary search on columns
        left, right = 0, n - 1
        while left < right:
            mid = (left + right) // 2
            # Find the maximum value in the mid column
            max_row = 0
            for i in range(1, m):
                if mat[i][mid] > mat[max_row][mid]:
                    max_row = i
            # Check if the max element in the mid column is a peak
            if mat[max_row][mid] > mat[max_row][mid - 1] and mat[max_row][mid] > mat[max_row][mid + 1]:
                return [max_row, mid]
            # Move towards the direction of higher value
            if mat[max_row][mid] > mat[max_row][mid + 1]:
                right = mid
            else:
                left = mid + 1

        # After loop, left == right, which is the column of a peak
        max_row = 0
        for i in range(1, m):
            if mat[i][left] > mat[max_row][left]:
                max_row = i
        return [max_row, left]
