class Solution:
    def maximumScore(self, scores: List[int], edges: List[List[int]]) -> int:
        # Build adjacency list
        graph = defaultdict(list)
        for u, v in edges:
            graph[u].append(v)
            graph[v].append(u)

        # For each node, keep track of top 3 neighbors by score
        # (node, score) pairs
        top1 = [-1, -1]  # (node, score)
        top2 = [-1, -1]
        top3 = [-1, -1]

        for node in range(len(scores)):
            # Update top3 with current node's neighbors
            for neighbor in graph[node]:
                # Use a helper function to update top3
                def update_top3(top1, top2, top3, node, score):
                    if score > top1[1]:
                        top3 = top1
                        top2 = top1
                        top1 = (node, score)
                    elif score > top2[1]:
                        top3 = top2
                        top2 = (node, score)
                    elif score > top3[1]:
                        top3 = (node, score)
                    return top1, top2, top3

                top1, top2, top3 = update_top3(top1, top2, top3, neighbor, scores[neighbor])

        max_score = -1
        for node in range(len(scores)):
            if len(graph[node]) < 2:
                continue  # Need at least 2 neighbors to form a path of length 3

            # Check all possible paths of length 3 starting from node
            for neighbor in graph[node]:
                if neighbor == top1[0]:
                    continue  # Skip if neighbor is the top1
                for next_neighbor in graph[neighbor]:
                    if next_neighbor == top1[0] or next_neighbor == top2[0]:
                        continue  # Skip if next_neighbor is top1 or top2
                    # Check if we can form a path of length 3
                    if next_neighbor in graph[neighbor] and neighbor in graph[node]:
                        # Check if the next_neighbor has a valid connection
                        if next_neighbor in graph[neighbor]:
                            # Form the path: node -> neighbor -> next_neighbor
                            # We need one more node to complete the path of length 4
                            for last_node in graph[next_neighbor]:
