            if s[i] in vowels:
                current_vowels += 1
        max_vowels = current_vowels
        # Slide the window
        for i in range(k, len(s)):
            if s[i - k] in vowels:
                current_vowels -= 1
            if s[i] in vowels:
                current_vowels += 1
            max_vowels = max(max_vowels, current_vowels)
