Here's the solution to the problem. The approach is to check for each point, the slope it makes with every other point. Points that share the same slope with a given point lie on the same line. We use a dictionary to count the number of points that share the same slope with a given point. We also need to handle vertical lines (infinite slope) and duplicate points (though the problem says all points are unique).

```python
from typing import List
from collections import defaultdict

class Solution:
    def maxPoints(self, points: List[List[int]]) -> int:
        if len(points) <= 1:
            return len(points)

        max_points = 0
        for i in range(len(points)):
            x1, y1 = points[i]
            slope_count = defaultdict(int)
            same_slope = 0
            for j in range(len(points)):
                if i == j:
                    continue
                x2, y2 = points[j]
                # Calculate the slope as a pair (dy, dx) in reduced form
                dy = y2 - y1
                dx = x2 - x1
                if dx == 0:
                    # Vertical line
                    slope = ('inf',)
                else:
                    # Reduce the fraction to its simplest form
                    gcd_val = gcd(dy, dx)
                    dy_reduced = dy // gcd_val
                    dx_reduced = dx // gcd_val
                    slope = (dy_reduced, dx_reduced)
                slope_count[slope] += 1
            # The maximum number of points with the same slope plus 1 (current point)
            max_points = max(max_points, max(slope_count.values(), default=0) + 1)

        return max_points

def gcd(a, b):
    while b:
        a, b = b, a % b
    return abs(a)

def run_tests():
    sol = Solution()
    print(sol.maxPoints([[1,1],[2,2],[3,3]]))  # Output: 3
    print(sol.maxPoints([[1,1],[3,2],[5,3],[4,1],[2,3],[1,4]]))  # Output: 4

run_tests()
