        thousands = ['Thousand', 'Million', 'Billion']

        def helper(n):
            if n == 0:
                return ''
            res = []
            if n >= 100:
                res.append(ones[n // 100] + ' Hundred')
                n %= 100
            if n >= 20:
                res.append(tens[n // 10])
                n %= 10
            elif 10 <= n < 20:
                res.append(teens[n - 10])
                n = 0
            if n > 0:
                res.append(ones[n])
            return ' '.join(res)

        # Break the number into chunks of three digits
        chunks = []
        while num > 0:
            chunks.append(num % 1000)
            num //= 1000

        # Process each chunk with appropriate scale
        result = []
        for i in range(len(chunks) - 1, -1, -1):
            chunk = chunks[i]
            if chunk != 0:
                part = helper(chunk)
                if i > 0:
                    part += ' ' + thousands[i - 1]
                result.append(part)

        return ' '.join(result)
