class Solution:
    def numberOfSpecialChars(self, word: str) -> int:
        # Dictionary to store the last occurrence of each lowercase letter
        last_lower = {}
        # Dictionary to store the first occurrence of each uppercase letter
        first_upper = {}

        for char in word:
            if char.islower():
                last_lower[char] = True  # Just need to know it exists
            else:
                first_upper[char.lower()] = True  # Store lowercase for comparison

        # Check for each letter if it has both lowercase and uppercase
        count = 0
        for c in last_lower:
            if c in first_upper:
                # Check if all lowercase occurrences are before the first uppercase
                # We can't directly check this with just first_upper, so we need to scan the string again
                # To optimize, we can track the first occurrence of each uppercase letter
                # and check if the last occurrence of lowercase is before that
                # But since we can't do that in one pass, we'll have to scan the string again
                # for each character to verify the condition

                # To optimize, let's track the first occurrence of each uppercase letter
                # and then check if the last occurrence of the lowercase is before it
                # Let's build a map of first occurrence of uppercase letters
                first_upper_pos = {c: None for c in first_upper}
                for i, char in enumerate(word):
                    if char.isupper():
                        first_upper_pos[char.lower()] = i

                # Now check if the last occurrence of lowercase is before the first occurrence of uppercase
                last_lower_pos = {c: None for c in last_lower}
                for i, char in enumerate(word):
                    if char.islower():
                        last_lower_pos[char] = i

                if last_lower_pos[c] < first_upper_pos[c]:
                    count += 1

        return count

