from collections import defaultdict
from typing import List

class Solution:
    def checkWays(self, pairs: List[List[int]]) -> int:
        graph = defaultdict(set)
        for u, v in pairs:
            graph[u].add(v)
            graph[v].add(u)

        nodes = list(graph.keys())
        degrees = {node: len(graph[node]) for node in nodes}

        # Check if root exists (node with maximum degree)
        root = max(nodes, key=lambda x: degrees[x])

        # Check if root has all other nodes in its adjacency list
        for node in nodes:
            if root not in graph[node]:
                return 0

        # Check for multiple valid trees
        has_multiple = False
        for node in nodes:
            if node == root:
                continue
            for neighbor in graph[node]:
                if degrees[neighbor] < degrees[node]:
                    if any(neighbor in graph[other] for other in graph[node]):
                        has_multiple = True
                        break
            if has_multiple:
                break

        return 2 if has_multiple else 1
