    def pathSum(self, nums: List[int]) -> int:
        total = 0
        # Build the tree using a dictionary
        tree = {}
        for num in nums:
            d = num // 100
            p = (num // 10) % 10
            v = num % 10
            tree[(d, p)] = v

        # Traverse the tree to calculate path sums
        def dfs(d, p, current_sum):
            nonlocal total
            current_sum += tree[(d, p)]
            # Check if it's a leaf node
            if not any((d+1, 2*p-1) in tree or (d+1, 2*p) in tree for _ in tree):
