class Solution:
    def minSwaps(self, s: str) -> int:
        n = len(s)
        count_0 = s.count('0')
        count_1 = n - count_0

        # If the counts differ by more than 1, it's impossible to make alternating
        if abs(count_0 - count_1) > 1:
            return -1

        # For even length, counts must be equal
        if n % 2 == 0:
            if count_0 != count_1:
                return -1

        # For odd length, one count must be one more than the other
        if n % 2 == 1:
            if abs(count_0 - count_1) != 1:
                return -1

        # Now calculate the number of mismatches for both possible patterns
        # Pattern 1: starts with '0' -> '010101...'
        # Pattern 2: starts with '1' -> '101010...'
        def count_mismatches(pattern):
            mismatches = 0
            for i in range(n):
                expected = pattern[i % 2]
                if s[i] != expected:
                    mismatches += 1
            return mismatches

        # For even length, both patterns are valid
        # For odd length, only one pattern is valid
        if n % 2 == 0:
            swaps1 = count_mismatches('010101')
            swaps2 = count_mismatches('101010')
            # Each swap fixes two mismatches, so divide by 2
            return min(swaps1 // 2, swaps2 // 2)
        else:
            if count_0 > count_1:
                swaps = count_mismatches('01010')
                return swaps // 2
            else:
                swaps = count_mismatches('10101')
                return swaps // 2

# Example usage (for testing):
def run_tests():
    sol = Solution()
    assert sol.minSwaps("111000") == 1
    assert sol.minSwaps("010") == 0
    assert sol.minSwaps("1110") == -1
    assert sol.minSwaps("01010") == 0
    assert sol.minSwaps("10101") == 0
    assert sol.minSwaps("011001") == 1
    print("All tests passed.")

