class Solution:
    def maximumSwap(self, num: int) -> int:
        digits = list(str(num))
        last_occurrence = {}

        # Store the last occurrence of each digit
        for i, d in enumerate(digits):
            last_occurrence[d] = i

        # Try to find the best swap
        for i in range(len(digits)):
            # Find the largest digit greater than digits[i]
            for d in reversed('9876543210'):
                if d > digits[i] and last_occurrence.get(d, -1) > i:
                    # Swap with the last occurrence of d
