from typing import List
import collections

class Solution:
    def minimumCost(self, target: str, words: List[str], costs: List[int]) -> int:
        # Preprocess words: for each word, store the minimum cost to get that word
        word_cost = {}
        for word, cost in zip(words, costs):
            if word in word_cost:
                word_cost[word] = min(word_cost[word], cost)
            else:
                word_cost[word] = cost

        # Dynamic programming: dp[i] is the minimum cost to form the first i characters of target
        dp = [float('inf')] * (len(target) + 1)
        dp[0] = 0

        for i in range(1, len(target) + 1):
            for word, cost in word_cost.items():
                if word == target[i - len(word):i]:
                    if dp[i - len(word)] + cost < dp[i]:
                        dp[i] = dp[i - len(word)] + cost

        return dp[len(target)] if dp[len(target)] != float('inf') else -1
