class Solution:
    def minSwaps(self, s: str) -> int:
        count_0 = s.count('0')
        count_1 = len(s) - count_0

        # Check if it's possible to form an alternating string
        if abs(count_0 - count_1) > 1:
            return -1

        # Determine the target pattern
        if count_0 > count_1:
            target = '01' * count_0
        else:
            target = '10' * count_1

        # Calculate the number of mismatches
        mismatches = 0
        for i in range(len(s)):
            if s[i] != target[i]:
                mismatches += 1

        # If even number of mismatches, return half of it (each swap fixes two mismatches)
        if mismatches % 2 == 0:
            return mismatches // 2
        else:
            return -1

def run_tests():
    # Test case 1
    sol = Solution()
    print(sol.minSwaps("111000"))  # Expected output: 1

    # Test case 2
    print(sol.minSwaps("010"))  # Expected output: 0

    # Test case 3
    print(sol.minSwaps("1110"))  # Expected output: -1
