class Solution:
    def smallestSubarrays(self, nums: List[int]) -> List[int]:
        n = len(nums)
        answer = [1] * n  # Initialize with 1 as the minimum subarray length is at least 1

        # We will track the maximum OR value for each starting index
        # and the corresponding minimum subarray length
        max_or = [0] * n
        for i in range(n):
            current_or = 0
            for j in range(i, n):
                current_or |= nums[j]
                if current_or == max_or[i] or max_or[i] == 0:
                    max_or[i] = current_or
                    answer[i] = j - i + 1
                else:
                    # If we already found a subarray with the same max_or but shorter length, we keep it
                    if current_or == max_or[i]:
                        answer[i] = min(answer[i], j - i + 1)

