class Solution:
    def minimumCost(self, sentence: str, k: int) -> int:
        words = sentence.split()
        n = len(words)
        dp = [float('inf')] * (n + 1)
        dp[0] = 0

        for i in range(1, n + 1):
            # Try to place the last word in the current row
            for j in range(i - 1, -1, -1):
                # Calculate the length of the row from words[j] to words[i-1]
                length = sum(len(words[m]) for m in range(j, i)) + (i - j - 1)  # add spaces
                if length <= k:
                    # If this is the last row, no cost is added
                    if i == n:
                        dp[i] = min(dp[i], dp[j])
                    else:
                        dp[i] = min(dp[i], dp[j] + (k - length) ** 2)
        return dp[n]
