class Solution:
    def validUtf8(self, data: List[int]) -> bool:
        i = 0
        while i < len(data):
            # Determine the number of bytes for the current character
            byte = data[i]
            if byte < 128:
                # 1-byte character
                i += 1
                continue
            elif byte >= 192 and byte < 224:
                # 2-byte character
                if i + 1 >= len(data):
                    return False
                if not (data[i + 1] >= 128 and data[i + 1] < 192):
                    return False
                i += 2
            elif byte >= 224 and byte < 240:
                # 3-byte character
                if i + 2 >= len(data):
                    return False
                if not (data[i + 1] >= 128 and data[i + 1] < 192):
                    return False
                if not (data[i + 2] >= 128 and data[i + 2] < 192):
                    return False
                i += 3
            elif byte >= 240 and byte < 248:
                # 4-byte character
                if i + 3 >= len(data):
                    return False
                if not (data[i + 1] >= 128 and data[i + 1] < 192):
                    return False
                if not (data[i + 2] >= 128 and data[i + 2] < 192):
                    return False
                if not (data[i + 3] >= 128 and data[i + 3] < 192):
                    return False
                i += 4
            else:
                # Invalid leading byte
                return False
        return True
