class Solution:
    def kEmptySlots(self, bulbs: List[int], k: int) -> int:
        from bisect import bisect_left, insort

        pos = []
        for day, bulb in enumerate(bulbs):
            idx = bisect_left(pos, bulb)
            if idx > 0 and idx - 1 >= 0:
                left = pos[idx - 1]
                if bulb - left - 1 == k:
                    return day + 1
            if idx < len(pos) and idx < len(pos):
                right = pos[idx]
                if right - bulb - 1 == k:
                    return day + 1
            insort(pos, bulb)
        return -1

