from typing import List

class Solution:
    def leadsToDestination(self, n: int, edges: List[List[int]], source: int, destination: int) -> bool:
        # Build adjacency list
        graph = [[] for _ in range(n)]
        for a, b in edges:
            graph[a].append(b)

        # Check if there's a cycle in any path from source to destination
        # and also ensure all paths from source end at destination
        visited = [False] * n
        path = set()
        has_cycle = False

        def dfs(node):
            nonlocal has_cycle
            if node == destination:
                # If destination is a leaf, it's valid
                if not graph[node]:
                    return True
                # If destination has outgoing edges, then all paths must end here
                # So we check all paths from here
                for neighbor in graph[node]:
                    if not dfs(neighbor):
                        return False
                return True

            if node in path:
                # Cycle detected
                has_cycle = True
                return False

            if visited[node]:
                return True  # Already processed

            visited[node] = True
            path.add(node)

            for neighbor in graph[node]:
                if not dfs(neighbor):
                    return False

            path.remove(node)
            return True

        # If source == destination and it's a leaf, it's valid
        if source == destination and not graph[source]:
            return True

        # Check if there's any path from source to destination
        if not dfs(source):
            return False

        # Check for cycles in any path from source to destination
        if has_cycle:
            return False

        # Ensure all paths from source end at destination
        # If destination has outgoing edges, then all paths from destination must end at destination
        if graph[destination]:
            # Check all paths from destination
            visited = [False] * n
            def dfs_check(node):
                if node == destination:
                    return True
                if visited[node]:
                    return False
                visited[node] = True
                for neighbor in graph[node]:
                    if not dfs_check(neighbor):
                        return False
                return True

            # If any path from destination doesn't end at destination, return False
            for neighbor in graph[destination]:
                if not dfs_check(neighbor):
                    return False

        return True

def run_tests():
    # Example 1
    print(Solution().leadsToDestination(3, [[0,1],[0,2]], 0, 2))  # Output: False
    # Example 2
    print(Solution().leadsToDestination(4, [[0,1],[0,3],[1,2],[2,1]], 0, 3))  # Output: False
    # Example 3
    print(Solution().leadsToDestination(4, [[0,1],[0,2],[1,3],[2,3]], 0, 3))  # Output: True

