class Solution:
    def findPairs(self, nums: List[int], k: int) -> int:
        nums.sort()
        seen = set()
        count = 0
        i, j = 0, 1
        while i < len(nums) and j < len(nums):
            diff = nums[j] - nums[i]
            if diff == k:
                if nums[i] not in seen:
                    seen.add(nums[i])
                    count += 1
                i += 1
                j += 1
            elif diff < k:
                j += 1
            else:
                i += 1
        return count
