from typing import List
import heapq

class Solution:
    def numberOfSets(self, n: int, maxDistance: int, roads: List[List[int]]) -> int:
        # Precompute all-pairs shortest paths using Floyd-Warshall algorithm
        dist = [[float('inf')] * n for _ in range(n)]
        for i in range(n):
            dist[i][i] = 0

        for u, v, w in roads:
            dist[u][v] = min(dist[u][v], w)
            dist[v][u] = min(dist[v][u], w)

        for k in range(n):
            for i in range(n):
                for j in range(n):
                    dist[i][j] = min(dist[i][j], dist[i][k] + dist[k][j])

        # Now, for each subset of nodes, check if all pairs in the subset have distance <= maxDistance
        # Since n is small (<=10), we can iterate through all subsets
        result = 0
        for mask in range(1 << n):
            valid = True
            for i in range(n):
                if (mask & (1 << i)) == 0:
                    continue
                for j in range(n):
                    if (mask & (1 << j)) == 0:
                        continue
                    if i == j:
                        continue
                    if dist[i][j] > maxDistance:
                        valid = False
                        break
                if not valid:
                    break
            if valid:
                result += 1
        return result

