class Solution:
    def encode(self, s: str) -> str:
        n = len(s)
        dp = [["" for _ in range(n)] for _ in range(n)]

        for i in range(n):
            for j in range(i, n):
                # Initialize with substring s[i:j+1]
                dp[i][j] = s[i:j+1]
                for k in range(i, j):
                    candidate = dp[i][k] + dp[k+1][j]
                    if len(candidate) < len(dp[i][j]):
                        dp[i][j] = candidate
                # Check for possible repetition
                for l in range(1, (j - i + 1) // 2 + 1):
                    if (j - i + 1) % l == 0:
                        repeat = dp[i][i + l - 1]
                        if repeat * ((j - i + 1) // l) == s[i:j+1]:
                            encoded = f"{(j - i + 1) // l}[{repeat}]"
                            if len(encoded) < len(dp[i][j]):
                                dp[i][j] = encoded
        return dp[0][n-1]

