class Solution:
    def numIslands2(self, m: int, n: int, positions: List[List[int]]) -> List[int]:
        parent = {}
        rank = {}
        result = []
        count = 0

        def find(x):
            if parent[x] != x:
                parent[x] = find(parent[x])
            return parent[x]

        def union(x, y):
            root_x = find(x)
            root_y = find(y)
            if root_x == root_y:
                return False
            if rank[root_x] < rank[root_y]:
                parent[root_x] = root_y
            else:
                parent[root_y] = root_x
                if rank[root_x] == rank[root_y]:
                    rank[root_x] += 1
            return True

        for r, c in positions:
            pos = r * n + c
            if pos in parent:
                result.append(count)
                continue
            parent[pos] = pos
            rank[pos] = 1
            count += 1

            # Check adjacent cells
            for dx, dy in [(-1, 0), (1, 0), (0, -1), (0, 1)]:
                nr, nc = r + dx, c + dy
                if 0 <= nr < m and 0 <= nc < n:
                    neighbor = nr * n + nc
                    if neighbor in parent:
                        if union(pos, neighbor):
                            count -= 1
            result.append(count)

        return result
