class Solution:
    def maximumBinaryString(self, binary: str) -> str:
        count_zero = binary.count('0')
        if count_zero <= 1:
            return binary

        n = len(binary)
        result = list(binary)
        ones = 0

        for i in range(n):
            if result[i] == '1':
                ones += 1
            else:
                if ones > 0:
                    result[i] = '1'
                    ones -= 1
                else:
                    result[i] = '0'

        return ''.join(result)
