from typing import List

class Solution:
    def shipWithinDays(self, weights: List[int], days: int) -> int:
        # Helper function to check if a given capacity is sufficient
        def is_possible(capacity):
            current_load = 0
            days_needed = 1
            for weight in weights:
                if current_load + weight > capacity:
                    days_needed += 1
                    current_load = 0
                current_load += weight
                if days_needed > days:
                    return False
            return True

        # Binary search between the maximum weight and the sum of all weights
        left = max(weights)
        right = sum(weights)

        while left < right:
            mid = (left + right) // 2
            if is_possible(mid):
                right = mid
            else:
                left = mid + 1

        return left
