class Solution:
    def numberOfPairs(self, points: List[List[int]]) -> int:
        n = len(points)
        count = 0

        for i in range(n):
            for j in range(n):
                if i == j:
                    continue
                # Check if Alice (i) can be upper left and Bob (j) lower right
                # Alice's x <= Bob's x and Alice's y >= Bob's y
                if points[i][0] <= points[j][0] and points[i][1] >= points[j][1]:
                    # Check if any other point is inside or on the rectangle
                    valid = True
                    for k in range(n):
                        if k == i or k == j:
                            continue
                        # Check if point k is inside or on the rectangle
                        if (points[k][0] >= points[i][0] and points[k][0] <= points[j][0] and
                            points[k][1] <= points[i][1] and points[k][1] >= points[j][1]):
                            valid = False
                            break
                    if valid:
                        count += 1
        return count
