class Solution:
    def rotatedDigits(self, n: int) -> int:
        # Mapping of each digit to its rotated counterpart
        rotate_map = {
            '0': '0', '1': '1', '8': '8',
            '2': '5', '5': '2', '6': '9', '9': '6'
        }
        # Digits that cannot be used (they rotate to invalid digits)
        invalid_digits = {'3', '4', '7'}

        count = 0
        for num in range(1, n + 1):
            s = str(num)
            rotated = ''
            valid = True
            for ch in s:
                if ch in invalid_digits:
                    valid = False
                    break
                rotated += rotate_map[ch]
            if valid and rotated != s:
                count += 1
        return count

