class Solution:
    def smallestSubsequence(self, s: str) -> str:
        from collections import Counter

        count = Counter(s)
        result = []
        seen = set()

        for char in s:
            if char in seen:
                continue
            while result and char < result[-1] and count[result[-1]] > 0:
                removed = result.pop()
                seen.remove(removed)
            result.append(char)
            seen.add(char)
            count[char] -= 1

        return ''.join(result)
