from typing import List
from collections import defaultdict, deque

class Solution:
    def groupStrings(self, words: List[str]) -> List[int]:
        # Convert each word into a bitmask
        def to_mask(word):
            mask = 0
            for c in word:
                mask |= 1 << (ord(c) - ord('a'))
            return mask

        # Create a mapping from mask to list of indices
        mask_to_indices = defaultdict(list)
        for i, word in enumerate(words):
            mask = to_mask(word)
            mask_to_indices[mask].append(i)

        # Build adjacency list for masks
        graph = defaultdict(list)

        # For each mask, check all possible masks that can be connected via one operation
        for mask in mask_to_indices:
            # Add one letter
            for i in range(26):
                if not (mask & (1 << i)):
                    new_mask = mask | (1 << i)
                    if new_mask in mask_to_indices:
                        for idx in mask_to_indices[new_mask]:
                            graph[mask].append(idx)
                            graph[new_mask].append(idx)

            # Remove one letter
            for i in range(26):
                if mask & (1 << i):
                    new_mask = mask ^ (1 << i)
                    if new_mask in mask_to_indices:
                        for idx in mask_to_indices[new_mask]:
                            graph[mask].append(idx)
                            graph[new_mask].append(idx)

            # Replace one letter
            for i in range(26):
                if mask & (1 << i):
                    for j in range(26):
                        if i != j:
                            new_mask = mask ^ (1 << i) ^ (1 << j)
                            if new_mask in mask_to_indices:
                                for idx in mask_to_indices[new_mask]:
                                    graph[mask].append(idx)
                                    graph[new_mask].append(idx)

        # Use Union-Find (Disjoint Set Union) to group connected components
        parent = {}
        def find(x):
            if parent[x] != x:
                parent[x] = find(parent[x])
            return parent[x]

        def union(x, y):
            root_x = find(x)
            root_y = find(y)
            if root_x != root_y:
                parent[root_y] = root_x

        # Initialize DSU
        for i in range(len(words)):
            parent[i] = i

        # Process all edges
        for mask in mask_to_indices:
            for idx in mask_to_indices[mask]:
                for neighbor in graph[mask]:
                    if find(idx) != find(neighbor):
                        union(idx, neighbor)

        # Count group sizes
        group_size = defaultdict(int)
        for i in range(len(words)):
            root = find(i)
            group_size[root] += 1

        max_groups = len(group_size)
        max_group_size = max(group_size.values())

        return [max_groups, max_group_size]
