class Solution:
    def robotWithString(self, s: str) -> str:
        # Step 1: Compute the smallest character to the right (inclusive) for each position
        n = len(s)
        min_right = [0] * n
        min_right[-1] = s[-1]
        for i in range(n-2, -1, -1):
            min_right[i] = min(s[i], min_right[i+1])

        # Step 2: Use a stack to simulate the robot's operations
        stack = []
        result = []

        for i in range(n):
            # Push characters from s to stack as long as the current character is <= the smallest remaining
            while stack and s[i] <= min_right[stack[-1]]:
                result.append(stack.pop())
            stack.append(i)

        # After processing all characters, pop remaining elements from stack
        while stack:
            result.append(stack.pop())

        return ''.join(result)
