class Solution:
    def minCapability(self, nums: List[int], k: int) -> int:
        # The minimum capability is the smallest value such that we can select at least k non-adjacent houses
        # with values <= that value. We can use binary search to find this value efficiently.

        def can_rob(cap):
            # Check if we can steal at least k houses with values <= cap
            count = 0
            skip = False
            for num in nums:
                if num <= cap:
                    if skip:
                        skip = False
                    else:
                        count += 1
                        if count >= k:
                            return True
                else:
                    skip = True
            return count >= k

        # Binary search between the minimum and maximum values in nums
        left, right = min(nums), max(nums)
        while left < right:
            mid = (left + right) // 2
            if can_rob(mid):
                right = mid
            else:
                left = mid + 1
        return left
