class Solution:
    def minimumSwap(self, s1: str, s2: str) -> int:
        # Count the number of positions where characters differ
        diff = 0
        # Count the number of "xy" and "yx" pairs in the differing positions
        xy = 0
        yx = 0

        for c1, c2 in zip(s1, s2):
            if c1 != c2:
                diff += 1
                if c1 == 'x' and c2 == 'y':
                    xy += 1
                else:
                    yx += 1

        # If the number of differing positions is odd, it's impossible to make the strings equal
        if diff % 2 != 0:
            return -1

        # Each "xy" and "yx" pair can be fixed with one swap
        # But two "xy" pairs can be fixed with one swap (swap the 'x' from one with the 'y' from the other)
        # Similarly for two "yx" pairs
        # So, the total number of swaps is (xy // 2) + (yx // 2) + (xy % 2) * 1 + (yx % 2) * 1
        # But since xy + yx is even, (xy % 2) == (yx % 2), so we can just add 1 if there's a remainder
        return (xy // 2) + (yx // 2) + (1 if (xy % 2) else 0)
