class Solution:
    def largestNumber(self, cost: List[int], target: int) -> str:
        # DP table to store the maximum length of the number for each target value
        dp = [-1] * (target + 1)
        dp[0] = 0  # Base case: 0 cost can form an empty string

        # For each target from 1 to target
        for t in range(1, target + 1):
            for i in range(9):
                if t >= cost[i] and dp[t - cost[i]] != -1:
                    if dp[t] < dp[t - cost[i]] + 1:
                        dp[t] = dp[t - cost[i]] + 1

        if dp[target] == -1:
            return "0"

        # Reconstruct the largest number
        res = []
        t = target
        while t > 0:
            for i in range(8, -1, -1):  # Try digits from 9 to 1
                if t >= cost[i] and dp[t] == dp[t - cost[i]] + 1:
                    res.append(str(i + 1))
                    t -= cost[i]
                    break
        return ''.join(res)

