class Solution:
    def subarrayBitwiseORs(self, arr: List[int]) -> int:
        current_or_set = set()
        result_set = set()

        for num in arr:
            new_or_set = set()
            new_or_set.add(num)
            for prev_or in current_or_set:
                new_or_set.add(prev_or | num)
            current_or_set = new_or_set
            result_set.update(current_or_set)

        return len(result_set)
