class Solution:
    def longestPalindrome(self, word1: str, word2: str) -> int:
        # Combine the two words into one for easier processing
        combined = word1 + word2
        n = len(combined)

        # dp[i][j] will store the length of the longest palindromic subsequence
        # between indices i and j in the combined string
        dp = [[0] * n for _ in range(n)]

        # Initialize the dp table for single characters
        for i in range(n):
            dp[i][i] = 1

        # Fill the dp table
        for length in range(2, n + 1):  # length of the substring
            for i in range(n - length + 1):
                j = i + length - 1
                if combined[i] == combined[j]:
                    dp[i][j] = 2 + dp[i + 1][j - 1]
                else:
                    dp[i][j] = max(dp[i + 1][j], dp[i][j - 1])

        # Check for palindromes that span both words
        max_len = 0
        for i in range(len(word1)):
            for j in range(len(word2)):
                if combined[i] == combined[len(word1) + j]:
                    max_len = max(max_len, 2 + dp[i + 1][len(word1) + j - 1])

        return max_len
