class Solution:
    def maximumTastiness(self, price: List[int], k: int) -> int:
        # Sort the prices to make it easier to find the minimum differences
        price.sort()

        # Binary search for the maximum possible tastiness
        def is_possible(tastiness):
            count = 1
            last = price[0]
            for p in price[1:]:
                if p - last >= tastiness:
                    count += 1
                    last = p
                    if count >= k:
                        return True
            return count >= k

        # Binary search bounds
        left, right = 0, price[-1] - price[0]

        # Perform binary search
        while left < right:
            mid = (left + right + 1) // 2
            if is_possible(mid):
                left = mid
            else:
                right = mid - 1

        return left
