    def makePalindrome(self, s: str) -> bool:
        n = len(s)
        changes = 0
        for i in range(n // 2):
            if s[i] != s[n - 1 - i]:
                changes += 1
        # For even length, changes is the number of mismatches
        # For odd length, we ignore the middle character
        # Now check if changes can be adjusted to 1 or 2
        # If the original number of changes is 0, then we need to make 2 changes
        # If the original number of changes is 1, then we need to make 1 change
        # If the original number of changes is 2, then we need to make 2 changes
        # If the original number of changes is more than 2, then it's not possible
        if changes == 0:
            return True  # can make with 2 changes
        elif changes == 1:
            return True  # can make with 1 change
        elif changes == 2:
            return True  # can make with 2 changes
        else:
