from typing import List
import heapq

class Solution:
    def numberOfSets(self, n: int, maxDistance: int, roads: List[List[int]]) -> int:
        # Build the graph
        graph = [[] for _ in range(n)]
        for u, v, w in roads:
            graph[u].append((v, w))
            graph[v].append((u, w))

        # Function to check if a subset of nodes is valid
        def is_valid(subset):
            if not subset:
                return True
            # Build the subgraph with the subset
            sub_graph = {node: [] for node in subset}
            for u, v, w in roads:
                if u in subset and v in subset:
                    sub_graph[u].append((v, w))
                    sub_graph[v].append((u, w))
            # Run Dijkstra's algorithm for each node in the subset
            for start in subset:
                dist = {node: float('inf') for node in subset}
                dist[start] = 0
                heap = [(0, start)]
                while heap:
                    d, node = heapq.heappop(heap)
                    if d > dist[node]:
                        continue
                    for neighbor, weight in sub_graph[node]:
                        if dist[neighbor] > d + weight:
                            dist[neighbor] = d + weight
                            heapq.heappush(heap, (dist[neighbor], neighbor))
                # Check if all nodes in subset are within maxDistance
                for node in subset:
                    if dist[node] > maxDistance:
                        return False
            return True

        # Generate all subsets of nodes
        result = 0
        for mask in range(1 << n):
            subset = [i for i in range(n) if (mask & (1 << i))]
            if is_valid(subset):
                result += 1
        return result
