class Solution:
    def alienOrder(self, words: List[str]) -> str:
        # Build the graph (adjacency list) and in-degree count
        graph = defaultdict(list)
        in_degree = defaultdict(int)

        # Initialize all unique characters
        all_chars = set()
        for word in words:
            for char in word:
                all_chars.add(char)

        # Build the graph from the words
