            # Find the first differing character
            min_len = min(len(word1), len(word2))
            for k in range(min_len):
                char1 = word1[k]
                char2 = word2[k]
                if char1 != char2:
                    # Add an edge from char1 to char2
                    if char2 not in graph[char1]:
                        graph[char1].append(char2)
                        in_degree[char2] += 1
                    break  # No need to check further once we find the first difference
            else:
                # If one word is a prefix of the other and the first is longer, it's invalid
                if len(word1) > len(word2):
                    return ""

        # Topological sort using Kahn's algorithm
        queue = deque([char for char in all_chars if in_degree[char] == 0])
        result = []

        while queue:
            char = queue.popleft()
            result.append(char)
            for neighbor in graph[char]:
                in_degree[neighbor] -= 1
                if in_degree[neighbor] == 0:
                    queue.append(neighbor)

        # Check if all characters were used (cycle detected)
        if len(result) != len(all_chars):
            return ""

        return ''.join(result)
