        num_to_index = {num: i for i, num in enumerate(arr)}

        for k in range(n):
            for i in range(k):
                j = num_to_index[arr[k] - arr[i]]
                if j < i:
                    dp[i][k] = dp[j][i] + 1
                    max_len = max(max_len, dp[i][k])

        return max_len if max_len >= 3 else 0
