class Solution:
    def secondsToRemoveOccurrences(self, s: str) -> int:
        n = len(s)
        time = 0
        zeros = 0
        ones = 0
        result = 0

        for i in range(n):
            if s[i] == '0':
                zeros += 1
            else:
                ones += 1

            # If we have a '0' and the previous character was '1', it's a potential '01' pair
            if s[i] == '0' and i > 0 and s[i-1] == '1':
                # The number of '1's before this '0' determines how long it will take for this '0' to move past all those '1's
                result = max(result, ones)
                # If there are more '1's than '0's before, the time is determined by the number of '1's
                if ones > zeros:
                    result = ones

        return result
