class Solution:
    def numberOfSubstrings(self, s: str) -> int:
        count = 0
        zeros = 0
        ones = 0
        left = 0
        n = len(s)

        for right in range(n):
            if s[right] == '0':
                zeros += 1
            else:
                ones += 1

            # Check if current substring has dominant ones
            while zeros * zeros > ones:
                if s[left] == '0':
                    zeros -= 1
                else:
                    ones -= 1
                left += 1

            # All substrings ending at 'right' and starting from 'left' to 'right' are valid
            count += left

        return count
