class Solution:
    def minCostII(self, costs: List[List[int]]) -> int:
        n = len(costs)
        k = len(costs[0])

        # Initialize dp array
        dp = [0] * k
        dp[0] = costs[0][0]

        for i in range(1, n):
            new_dp = [float('inf')] * k
            for j in range(k):
                for l in range(k):
                    if l != j:
                        new_dp[j] = min(new_dp[j], dp[l] + costs[i][j])
