class Solution:
    def scoreOfParentheses(self, s: str) -> int:
        stack = []
        score = 0
        for char in s:
            if char == '(':
                stack.append(0)
            else:
                top = stack.pop()
                if top == 0:
                    score += 1
                else:
                    score += 2 * top
                if stack:
                    stack[-1] += score
                else:
                    score = 0
        return score

def run_tests():
