from typing import List
from functools import lru_cache

class Solution:
    def cherryPickup(self, grid: List[List[int]]) -> int:
        rows, cols = len(grid), len(grid[0])

        @lru_cache(None)
        def dfs(r, c1, c2):
            # If we are at the bottom row, return the collected cherries
            if r == rows:
                return 0

            # Calculate the cherries collected by both robots
            # If both are at the same cell, only count once
            if c1 == c2:
                cherries = grid[r][c1]
            else:
                cherries = grid[r][c1] + grid[r][c2]

            max_cherries = 0
            # Try all possible moves for both robots
            for dc1 in (-1, 0, 1):
                for dc2 in (-1, 0, 1):
                    new_c1 = c1 + dc1
                    new_c2 = c2 + dc2
                    # Check if new positions are valid
                    if 0 <= new_c1 < cols and 0 <= new_c2 < cols:
                        max_cherries = max(max_cherries, dfs(r + 1, new_c1, new_c2))

            return cherries + max_cherries

        return dfs(0, 0, cols - 1)
