from typing import List
import math

class Solution:
    def bestCoordinate(self, towers: List[List[int]], radius: int) -> List[int]:
        max_quality = -1
        result = [0, 0]

        for x in range(51):
            for y in range(51):
                quality = 0
                for tx, ty, q in towers:
                    d = math.sqrt((x - tx)**2 + (y - ty)**2)
                    if d <= radius:
                        quality += q // (1 + d)
                if quality > max_quality or (quality == max_quality and [x, y] < result):
                    max_quality = quality
                    result = [x, y]
        return result
