class Solution:
    def minWindow(self, s1: str, s2: str) -> str:
        n, m = len(s1), len(s2)
        if m == 0 or n < m:
            return ""

        # dp[i][j] will store the index in s1 where the subsequence of s2[0..i] ends in s1[0..j]
        dp = [[-1] * (n + 1) for _ in range(m + 1)]

        # Initialize the first column since we need to match the first character of s2
        for i in range(n):
            if s1[i] == s2[0]:
                dp[1][i + 1] = i

        # Fill the dp table
        for i in range(2, m + 1):
            for j in range(1, n + 1):
                if s1[j - 1] == s2[i - 1]:
                    # Check if the previous character in s2 can be matched in s1 before j
                    if dp[i - 1][j - 1] != -1:
                        dp[i][j] = j - 1

        # Find the minimum window
        min_len = float('inf')
        result_start = -1
        for j in range(1, n + 1):
            if dp[m][j] != -1:
                window_len = j - dp[m][j]
                if window_len < min_len:
                    min_len = window_len
                    result_start = dp[m][j]

        if result_start == -1:
            return ""
        return s1[result_start:result_start + min_len]
