class Solution:
    def calculate(self, s: str) -> int:
        def helper(s, index):
            stack = []
            num = 0
            sign = '+'

            while index < len(s):
                char = s[index]
                if char.isdigit():
                    num = num * 10 + int(char)
                elif char == '(':
                    num, index = helper(s, index + 1)
                if char in '+-*/()':
                    if sign == '+':
                        stack.append(num)
                    elif sign == '-':
                        stack.append(-num)
                    elif sign == '*':
                        stack[-1] = stack[-1] * num
                    elif sign == '/':
                        # Division truncates toward zero
                        stack[-1] = int(stack[-1] / num)
                    sign = char
                    num = 0
                index += 1

            if sign == '+':
                stack.append(num)
            elif sign == '-':
                stack.append(-num)
            elif sign == '*':
                stack[-1] = stack[-1] * num
            elif sign == '/':
                stack[-1] = int(stack[-1] / num)

            return sum(stack), index

        result, _ = helper(s, 0)
        return result

