from typing import List
from collections import deque

class Solution:
    def maxDistance(self, grid: List[List[int]]) -> int:
        n = len(grid)
        q = deque()
        # Initialize the queue with all land cells (1s)
        for i in range(n):
            for j in range(n):
                if grid[i][j] == 1:
                    q.append((i, j))

        # Directions for moving in 4 directions (up, down, left, right)
        directions = [(-1, 0), (1, 0), (0, -1), (0, 1)]
        max_distance = 0
        # BFS to find the maximum distance from any water cell to the nearest land
        while q:
            x, y = q.popleft()
            for dx, dy in directions:
                nx, ny = x + dx, y + dy
                if 0 <= nx < n and 0 <= ny < n and grid[nx][ny] == 0:
                    grid[nx][ny] = grid[x][y] + 1
                    max_distance = max(max_distance, grid[nx][ny])
                    q.append((nx, ny))

        # If all cells are land, return -1
        if max_distance == 0 and any(1 in row for row in grid):
            return -1
        return max_distance - 1
