class Solution:
    def maxValue(self, n: int, index: int, maxSum: int) -> int:
        def is_possible(value):
            # Calculate the minimum sum required if nums[index] is 'value'
            # The array is constructed such that nums[index] is the maximum and values decrease by 1 as we move away
            left = max(1, value - index)
            right = max(1, value - (n - 1 - index))
            total = value + (value - 1) * (index) // 2 + (value - 1) * (n - 1 - index) // 2
            return total <= maxSum

        # Binary search between 1 and maxSum
        left, right = 1, maxSum
        while left < right:
            mid = (left + right + 1) // 2
            if is_possible(mid):
                left = mid
            else:
                right = mid - 1
        return left
