class Solution:
    def getAverages(self, nums: List[int], k: int) -> List[int]:
        n = len(nums)
        avgs = [-1] * n
        window_size = 2 * k + 1

        if window_size > n:
            return avgs

        # Precompute prefix sums
        prefix = [0] * (n + 1)
        for i in range(n):
            prefix[i + 1] = prefix[i] + nums[i]

        for i in range(n):
            if i - k < 0 or i + k >= n:
                continue
            total = prefix[i + k + 1] - prefix[i - k]
            avgs[i] = total // window_size

        return avgs
