class Solution:
    def findTheString(self, lcp: List[List[int]]) -> str:
        n = len(lcp)
        word = [''] * n

        # Check if the lcp matrix is valid
        for i in range(n):
            for j in range(n):
                if i == j:
                    if lcp[i][j] != n - i:
                        return ""
                else:
                    if lcp[i][j] != lcp[j][i]:
                        return ""

        # Try to build the word
        for i in range(n):
            # If we haven't assigned a character yet
            if word[i] == '':
                # Assign the smallest possible character
                word[i] = 'a'
                # Propagate the character to the rest of the string
                for j in range(i + 1, n):
                    if lcp[i][j] > 0:
                        # The next character must be the same as the previous one
                        if word[j] == '':
                            word[j] = word[i]
                        else:
                            if word[j] != word[i]:
                                return ""
                    else:
                        # The next character must be different
                        if word[j] == '':
                            # Try the smallest possible different character
                            for c in 'abcdefghijklmnopqrstuvwxyz':
                                if c != word[i]:
                                    word[j] = c
                                    break
                        else:
                            if word[j] == word[i]:
                                return ""

        # Final check: verify the lcp matrix
        for i in range(n):
            for j in range(n):
                if i == j:
                    if lcp[i][j] != n - i:
                        return ""
                else:
                    if lcp[i][j] != lcp[j][i]:
                        return ""
                    # Check if the prefix length is correct
                    if lcp[i][j] > 0:
                        if word[i] != word[j]:
                            return ""
                    else:
                        if word[i] == word[j]:
                            return ""

        return ''.join(word)
