from typing import List

class Solution:
    def numberOfPairs(self, points: List[List[int]]) -> int:
        n = len(points)
        count = 0

        # Iterate over all possible pairs of points (Alice, Bob)
        for i in range(n):
            for j in range(n):
                if i == j:
                    continue
                # Check if Alice (points[i]) is upper left and Bob (points[j]) is lower right
                # Alice's x must be <= Bob's x and Alice's y must be >= Bob's y
                if points[i][0] <= points[j][0] and points[i][1] >= points[j][1]:
                    # Check if any other point is inside or on the rectangle
                    valid = True
                    for k in range(n):
                        if k == i or k == j:
                            continue
                        x, y = points[k]
                        # Check if point is inside or on the rectangle
                        if (x >= points[i][0] and x <= points[j][0] and
                            y <= points[i][1] and y >= points[j][1]):
                            valid = False
                            break
                    if valid:
                        count += 1
        return count
