class Solution:
    def maxNumber(self, nums1: List[int], nums2: List[int], k: int) -> List[int]:
        def merge(a, b):
            # Merges two non-decreasing arrays into the largest possible array
            result = []
            i = j = 0
            while i < len(a) and j < len(b):
                if a[i] > b[j]:
                    result.append(a[i])
                    i += 1
                elif a[i] < b[j]:
                    result.append(b[j])
                    j += 1
                else:
                    # If equal, choose the one that leads to a larger sequence
                    # Compare the remaining parts
                    if a[i:] > b[j:]:
                        result.append(a[i])
                        i += 1
                    else:
                        result.append(b[j])
                        j += 1
            # Add the remaining elements
            result.extend(a[i:])
            result.extend(b[j:])
            return result

        def max_subsequence(arr, k):
            # Finds the maximum subsequence of length k from arr
            # Maintains the relative order of elements
            stack = []
            for i, num in enumerate(arr):
                # If we can remove elements from the stack to make room for larger numbers
                while stack and stack[-1] < num and len(stack) + len(arr) - i > k:
                    stack.pop()
                if len(stack) < k:
                    stack.append(num)
            return stack

        max_result = []
        # Try all possible splits of k between nums1 and nums2
        for i in range(0, k + 1):
            if i <= len(nums1) and k - i <= len(nums2):
                sub1 = max_subsequence(nums1, i)
                sub2 = max_subsequence(nums2, k - i)
                merged = merge(sub1, sub2)
                if merged > max_result:
                    max_result = merged
        return max_result
