class Solution:
    def smallestSubsequence(self, s: str) -> str:
        # Last occurrence of each character
        last_occurrence = {char: idx for idx, char in enumerate(s)}

        # Use a stack to build the result
        stack = []
        seen = set()

        for idx, char in enumerate(s):
            # If the character is already in the result, skip it
            if char in seen:
                continue

            # While the stack is not empty, and the current character is smaller than the top of the stack
            # and the top of the stack appears later in the string, we pop it
            while stack and char < stack[-1] and last_occurrence[stack[-1]] > idx:
                removed = stack.pop()
                seen.remove(removed)

            # Add the current character to the stack and mark it as seen
            stack.append(char)
            seen.add(char)

        return ''.join(stack)
