            return 0

        write_index = 0
        current_char = chars[0]
        count = 1

        for i in range(1, len(chars)):
            if chars[i] == current_char:
                count += 1
            else:
                # Write the current character and count to the array
                chars[write_index] = current_char
                write_index += 1
