class Solution:
    def validSubarraySize(self, nums: List[int], threshold: int) -> int:
        n = len(nums)
        max_len = -1
        min_right = [0] * n
        min_right[-1] = nums[-1]
        for i in range(n-2, -1, -1):
            min_right[i] = min(nums[i], min_right[i+1])

        stack = []
        for i in range(n):
            while stack and nums[i] < nums[stack[-1]]:
                idx = stack.pop()
                if nums[idx] > threshold / (i - idx):
                    max_len = max(max_len, i - idx)
            stack.append(i)

        for k in range(n, 0, -1):
            if max_len >= k:
                return k
        return -1
