class Solution:
    def numPermsDISequence(self, s: str) -> int:
        MOD = 10**9 + 7
        n = len(s)
        # dp[i][j] represents the number of valid permutations of length i+1 ending with the j-th smallest remaining number
        dp = [[0] * (n + 1) for _ in range(n + 1)]
        dp[0][0] = 1  # base case: one way to arrange 0 elements

        for i in range(1, n + 1):
            for j in range(i + 1):
                if s[i - 1] == 'I':
                    # If the last step is 'I', we can append a number larger than the last one
                    for k in range(j):
                        dp[i][j] = (dp[i][j] + dp[i - 1][k]) % MOD
                else:
                    # If the last step is 'D', we can append a number smaller than the last one
                    for k in range(j, i):
                        dp[i][j] = (dp[i][j] + dp[i - 1][k]) % MOD

        # Sum all possibilities for the full sequence
        return sum(dp[n][j] for j in range(n + 1)) % MOD
