class Solution:
    def addMinimum(self, word: str) -> int:
        # We will track the current position in the "abc" sequence
        current = 'a'
        insertions = 0

        for char in word:
            # Determine the number of steps needed to reach the current character from 'a'
            if current == 'a':
                if char == 'a':
                    pass  # No insertion needed
                elif char == 'b':
                    insertions += 1
                elif char == 'c':
                    insertions += 2
            elif current == 'b':
                if char == 'b':
                    insertions += 1
                elif char == 'c':
                    pass  # No insertion needed
                elif char == 'a':
                    insertions += 2
            elif current == 'c':
                if char == 'c':
                    pass  # No insertion needed
                elif char == 'a':
                    insertions += 1
                elif char == 'b':
                    insertions += 2

            # Update current to the next character in the sequence
            if char == 'a':
                current = 'a'
            elif char == 'b':
                current = 'b'
            elif char == 'c':
                current = 'c'

        # After processing all characters, check if we need to complete the last "abc" sequence
        if current != 'c':
            insertions += (3 - (ord(current) - ord('a'))) % 3

        return insertions

