            for neighbor in tree[node]:
                if neighbor != parent:
                    total += dfs(neighbor, node)
            subtree_sums.append(total)
            return total

        dfs(0, -1)

        # Build a trie for maximum XOR
        class TrieNode:
            def __init__(self):
                self.children = [None, None]

        root = TrieNode()
        max_xor = 0

        # Insert all subtree sums into trie
        for s in subtree_sums:
            node = root
            for bit in reversed(range(32)):
                bit_val = (s >> bit) & 1
                if not node.children[bit_val]:
                    node.children[bit_val] = TrieNode()
                node = node.children[bit_val]

