from functools import lru_cache

class Solution:
    def maxJumps(self, arr: List[int], d: int) -> int:
        n = len(arr)

        @lru_cache(None)
        def dfs(i):
            max_count = 1
            # Jump to the right
            for j in range(i + 1, min(i + d + 1, n)):
                if arr[i] <= arr[j]:
                    break
                # Check if all elements between i and j are less than arr[i]
                for k in range(i + 1, j):
                    if arr[k] >= arr[i]:
                        break
                else:
                    max_count = max(max_count, 1 + dfs(j))
            # Jump to the left
            for j in range(i - 1, max(i - d - 1, -1), -1):
                if arr[i] <= arr[j]:
                    break
                # Check if all elements between i and j are less than arr[i]
                for k in range(j + 1, i):
                    if arr[k] >= arr[i]:
                        break
                else:
                    max_count = max(max_count, 1 + dfs(j))
            return max_count

        return max(dfs(i) for i in range(n))
