class Solution:
    def numSpecialEquivGroups(self, words: List[str]) -> int:
        def get_key(word):
            # Separate even and odd indexed characters
            even = ''.join(word[::2])
            odd = ''.join(word[1::2])
            # Return a tuple of sorted even and odd parts to form a unique key
            return (sorted(even), sorted(odd))

        # Use a set to count unique groups
        groups = set()
        for word in words:
            groups.add(get_key(word))

        # The number of unique groups is the answer
        return len(groups)
