class Solution:
    def judgePoint24(self, cards: List[int]) -> bool:
        def dfs(nums):
            if len(nums) == 1:
                return abs(nums[0] - 24) < 1e-6
            for i in range(len(nums)):
                for j in range(len(nums)):
                    if i != j:
                        a, b = nums[i], nums[j]
                        new_nums = []
                        for k in range(len(nums)):
                            if k != i and k != j:
                                new_nums.append(nums[k])
                        # Try all operations
                        new_nums.append(a + b)
                        if not dfs(new_nums):
                            new_nums.pop()
                            new_nums.append(a - b)
                            if not dfs(new_nums):
                                new_nums.pop()
                                new_nums.append(a * b)
                                if not dfs(new_nums):
                                    new_nums.pop()
                                    if b != 0:
