from typing import List
from collections import Counter

class Solution:
    def findSubstring(self, s: str, words: List[str]) -> List[int]:
        if not words or not s:
            return []

        word_len = len(words[0])
        num_words = len(words)
        total_len = word_len * num_words
        word_count = Counter(words)
        result = []

        for i in range(word_len):
            left = i
            current_count = Counter()
            words_found = 0

            for right in range(i, len(s), word_len):
                word = s[right:right + word_len]
                if word in word_count:
                    current_count[word] += 1
                    if current_count[word] == word_count[word]:
                        words_found += 1
                    elif current_count[word] == word_count[word] + 1:
                        words_found -= 1

                while words_found == num_words:
                    if right - left + 1 == total_len:
                        result.append(left)
                    word_left = s[left:left + word_len]
                    if current_count[word_left] == word_count[word_left]:
                        words_found -= 1
                    current_count[word_left] -= 1
                    left += word_len

        return result
