from typing import List
import itertools

class Solution:
    def beautifulPair(self, nums1: List[int], nums2: List[int]) -> List[int]:
        n = len(nums1)
        min_distance = float('inf')
        beautiful_pairs = []

        # Generate all possible pairs (i, j) where i < j
        for i in range(n):
            for j in range(i + 1, n):
                distance = abs(nums1[i] - nums1[j]) + abs(nums2[i] - nums2[j])
                if distance < min_distance:
                    min_distance = distance
                    beautiful_pairs = [(i, j)]
                elif distance == min_distance:
                    beautiful_pairs.append((i, j))

        # Find the lexicographically smallest pair
        beautiful_pairs.sort()
        return list(beautiful_pairs[0])
