class Solution:
    def xorGame(self, nums: List[int]) -> bool:
        total_xor = 0
        for num in nums:
            total_xor ^= num

        if total_xor == 0:
            return True  # Alice wins immediately

        # If there's only one number left, Alice will lose
        if len(nums) == 1:
            return False

        # If the total XOR is not zero, the game is determined by parity
        # If the number of elements is even, Alice can always win
        # If the number of elements is odd, Alice will lose
        return len(nums) % 2 == 0
