class Solution:
    def soupServings(self, n: int) -> float:
        # Convert n to the number of 25ml units
        n = (n + 24) // 25  # Round up to the nearest multiple of 25

        # Memoization cache
        memo = {}

        def dp(a, b):
            if (a, b) in memo:
                return memo[(a, b)]
            if a <= 0 and b <= 0:
                return 0.5  # Both empty, return half probability
            if a <= 0:
                return 1.0  # A is empty, B not
            if b <= 0:
                return 0.0  # B is empty, A not

            # Calculate the probability for each operation
            prob = 0.25 * (dp(a - 4, b) + dp(a - 3, b - 1) + dp(a - 2, b - 2) + dp(a - 1, b - 3))
            memo[(a, b)] = prob
            return prob

        return dp(n, n)
