from typing import List
from math import gcd
from functools import reduce

class Solution:
    def subarrayGCD(self, nums: List[int], k: int) -> int:
        count = 0
        n = len(nums)

        for i in range(n):
            current_gcd = 0
            for j in range(i, n):
                current_gcd = gcd(current_gcd, nums[j])
                if current_gcd == k:
                    count += 1
                elif current_gcd > k:
                    break  # GCD can't become smaller than current_gcd, so break early
        return count
