class Solution:
    def findInteger(self, k: int, digit1: int, digit2: int) -> int:
        # Handle the case where digit1 and digit2 are the same and zero
        if digit1 == digit2 == 0:
            return -1

        # Generate numbers composed of digit1 and digit2
        # Use BFS to generate numbers in increasing order
        from collections import deque

        queue = deque()
        # Start with digits digit1 and digit2 (if they are not zero)
        if digit1 != 0:
            queue.append(digit1)
        if digit2 != 0 and digit2 != digit1:
            queue.append(digit2)

        # The maximum value for a 32-bit signed integer
        max_int = 2**31 - 1

        while queue:
            num = queue.popleft()
            if num > k and num <= max_int and num % k == 0:
                return num
            # Generate next numbers by appending digit1 and digit2
            for d in [digit1, digit2]:
                new_num = num * 10 + d
                if new_num <= max_int:
                    queue.append(new_num)

        # If no such number is found
        return -1
