from typing import List

class Solution:
    def fullJustify(self, words: List[str], maxWidth: int) -> List[str]:
        result = []
        line = []
        chars = 0

        for word in words:
            if chars + len(word) + (len(line) > 0) <= maxWidth:
                line.append(word)
                chars += len(word)
                if len(line) > 1:
                    chars += 1  # Add space between words
            else:
                # Justify the current line
                if len(line) == 1:
                    # Left-justify with spaces at the end
                    result.append(line[0] + ' ' * (maxWidth - chars))
                else:
                    # Distribute spaces evenly
                    total_spaces = maxWidth - chars
                    spaces_per_gap = total_spaces // (len(line) - 1)
                    extra_spaces = total_spaces % (len(line) - 1)
                    justified_line = ''
                    for i in range(len(line)):
                        justified_line += line[i]
                        if i < len(line) - 1:
                            justified_line += ' ' * (spaces_per_gap + (1 if extra_spaces > 0 else 0))
                            extra_spaces -= 1
                    result.append(justified_line)
                # Start a new line
                line = [word]
                chars = len(word)
                if len(line) > 1:
                    chars += 1  # Add space between words

        # Add the last line
        if line:
            if len(line) == 1:
                result.append(line[0] + ' ' * (maxWidth - chars))
            else:
                total_spaces = maxWidth - chars
                spaces_per_gap = total_spaces // (len(line) - 1)
                extra_spaces = total_spaces % (len(line) - 1)
                justified_line = ''
                for i in range(len(line)):
                    justified_line += line[i]
                    if i < len(line) - 1:
                        justified_line += ' ' * (spaces_per_gap + (1 if extra_spaces > 0 else 0))
                        extra_spaces -= 1
                result.append(justified_line)

        return result
