The idea is to count the number of ways to form sequences of length `n` ending with a certain value, where each value is a multiple of the previous one.

```python
import sys
import math
from functools import lru_cache

MOD = 10**9 + 7

class Solution:
    def idealArrays(self, n: int, maxValue: int) -> int:
        @lru_cache(maxsize=None)
        def dp(pos, last, current_val):
            if pos == n:
                return 1
            res = 0
            for next_val in range(current_val, maxValue + 1):
                if next_val % last == 0:
                    res += dp(pos + 1, next_val, next_val)
                    res %= MOD
            return res

        total = 0
        for start in range(1, maxValue + 1):
            total += dp(1, start, start)
            total %= MOD

        return total

def run_tests():
