from collections import deque
from typing import List

class Solution:
    def shortestPath(self, grid: List[List[int]], k: int) -> int:
        m, n = len(grid), len(grid[0])
        if grid[0][0] == 1:
            return -1  # starting point is an obstacle

        # Directions: up, down, left, right
        directions = [(-1, 0), (1, 0), (0, -1), (0, 1)]

        # (row, col, remaining_k)
        queue = deque([(0, 0, k)])
        visited = [[[False] * (k + 1) for _ in range(n)] for _ in range(m)]
        visited[0][0][k] = True
        steps = 0

        while queue:
            for _ in range(len(queue)):
                r, c, rem_k = queue.popleft()

                if r == m - 1 and c == n - 1:
                    return steps

                for dr, dc in directions:
                    nr, nc = r + dr, c + dc
                    if 0 <= nr < m and 0 <= nc < n:
                        if not visited[nr][nc][rem_k]:
                            if grid[nr][nc] == 0:
                                visited[nr][nc][rem_k] = True
                                queue.append((nr, nc, rem_k))
                            else:
                                if rem_k > 0:
                                    visited[nr][nc][rem_k - 1] = True
                                    queue.append((nr, nc, rem_k - 1))
            steps += 1

        return -1
