class Solution:
    def punishmentNumber(self, n: int) -> int:
        def can_split(s, target):
            # Helper function to check if the string s can be split into parts that sum to target
            if not s:
                return target == 0
            for i in range(1, len(s) + 1):
                part = s[:i]
                if part[0] == '0' and len(part) > 1:
                    continue  # Skip leading zeros
                if can_split(s[i:], target - int(part)):
                    return True
            return False

        total = 0
        for i in range(1, n + 1):
            square = str(i * i)
            if can_split(square, i):
                total += i * i
        return total

