class Solution:
    def maxDiff(self, num: int) -> int:
        def replace_all(s, x, y):
            return s.replace(str(x), str(y))

        # Convert num to string to process digits
        s = str(num)

        # Generate all possible a values (first operation)
        a_values = []
        for x in range(10):
            for y in range(10):
                if x == y:
                    continue
                new_str = replace_all(s, x, y)
                if new_str[0] != '0' and new_str != '0':
                    a_values.append(int(new_str))

        # Generate all possible b values (second operation)
        b_values = []
        for x in range(10):
            for y in range(10):
                if x == y:
                    continue
                new_str = replace_all(s, x, y)
                if new_str[0] != '0' and new_str != '0':
                    b_values.append(int(new_str))

        # Compute max difference
        max_diff = 0
        for a in a_values:
            for b in b_values:
                max_diff = max(max_diff, abs(a - b))

        return max_diff
