class Solution:
    def circularArrayLoop(self, nums: List[int]) -> bool:
        n = len(nums)
        for i in range(n):
            if nums[i] == 0:
                continue
            slow, fast = i, i
            # Check for direction consistency and cycle
            while True:
                # Move slow one step
                slow = (slow + nums[slow]) % n
                # Move fast two steps
                fast = (fast + nums[fast]) % n
                fast = (fast + nums[fast]) % n
                # Check if cycle exists
                if slow == fast:
                    # Check if the cycle has length > 1
                    if slow == (slow + nums[slow]) % n:
                        break
                    else:
                        # Cycle of length 1, not valid
                        break
                # Check if direction is consistent
                if (nums[slow] < 0 and nums[fast] >= 0) or (nums[slow] >= 0 and nums[fast] < 0):
                    break
                # Check if the value is zero (already visited)
                if nums[slow] == 0 or nums[fast] == 0:
                    break
            # If we found a valid cycle
            if slow == fast and slow != (slow + nums[slow]) % n:
                return True
            # Mark visited elements to avoid reprocessing
            while i < n and nums[i] != 0:
                next_index = (i + nums[i]) % n
                nums[i], nums[next_index] = 0, 0
                i = next_index
        return False
