class Solution:
    def shortestCommonSupersequence(self, str1: str, str2: str) -> str:
        # First, find the longest common subsequence (LCS)
        m, n = len(str1), len(str2)
        lcs = [[0]*(n+1) for _ in range(m+1)]

        for i in range(1, m+1):
            for j in range(1, n+1):
                if str1[i-1] == str2[j-1]:
                    lcs[i][j] = lcs[i-1][j-1] + 1
                else:
                    lcs[i][j] = max(lcs[i-1][j], lcs[i][j-1])

        # Now reconstruct the LCS
        i, j = m, n
        lcs_str = []
        while i > 0 and j > 0:
            if str1[i-1] == str2[j-1]:
                lcs_str.append(str1[i-1])
                i -= 1
                j -= 1
            else:
                if lcs[i-1][j] > lcs[i][j-1]:
                    lcs_str.append(str1[i-1])
                    i -= 1
                else:
                    lcs_str.append(str2[j-1])
                    j -= 1

        lcs_str = ''.join(reversed(lcs_str))

        # Now build the SCS
        res = []
        i, j = 0, 0
        for c in lcs_str:
            while i < len(str1) and str1[i] != c:
                res.append(str1[i])
                i += 1
            while j < len(str2) and str2[j] != c:
                res.append(str2[j])
                j += 1
            res.append(c)
            i += 1
            j += 1

        # Add remaining characters from str1 and str2
        while i < len(str1):
            res.append(str1[i])
            i += 1
        while j < len(str2):
            res.append(str2[j])
            j += 1

        return ''.join(res)
