from typing import List

class Solution:
    def maxScore(self, nums: List[int], x: int) -> int:
        # Initialize max scores for even and odd parity
        even_max = odd_max = float('-inf')

        # We start with nums[0], so check its parity
        if nums[0] % 2 == 0:
            even_max = nums[0]
        else:
            odd_max = nums[0]

        # Iterate from the second element
        for i in range(1, len(nums)):
            num = nums[i]
            parity = num % 2

            # Calculate the max score if we take this number
            if parity == 0:
                current = max(even_max, odd_max - x) + num
            else:
                current = max(odd_max, even_max - x) + num

            # Update the max scores
            if parity == 0:
                even_max = max(even_max, current)
            else:
                odd_max = max(odd_max, current)

        # Return the maximum of even and odd max scores
        return max(even_max, odd_max)
