from math import gcd
from itertools import permutations

class Solution:
    def selfDivisiblePermutationCount(self, n: int) -> int:
        def is_self_divisible(arr):
            for i in range(n):
                if gcd(arr[i], i + 1) != 1:
                    return False
            return True

        count = 0
        for perm in permutations(range(1, n + 1)):
            if is_self_divisible(perm):
                count += 1
        return count

