import heapq

class Solution:
    def kthLargestValue(self, matrix: List[List[int]], k: int) -> int:
        m, n = len(matrix), len(matrix[0])
        dp = [[0] * n for _ in range(m)]
        values = []

        for i in range(m):
            for j in range(n):
                dp[i][j] = matrix[i][j]
                if i > 0:
                    dp[i][j] ^= dp[i-1][j]
                if j > 0:
                    dp[i][j] ^= dp[i][j-1]
                if i > 0 and j > 0:
                    dp[i][j] ^= dp[i-1][j-1]
                heapq.heappush(values, dp[i][j])

        result = []
        while len(result) < k:
            result.append(heapq.heappop(values))

        return result[-1]

