from typing import List

class Solution:
    def minSum(self, nums1: List[int], nums2: List[int]) -> int:
        sum1 = sum(nums1)
        sum2 = sum(nums2)

        zeros1 = nums1.count(0)
        zeros2 = nums2.count(0)

        # If there are no zeros in both arrays, check if sums are already equal
        if zeros1 == 0 and zeros2 == 0:
            return sum1 if sum1 == sum2 else -1

        # If there are no zeros in one array, we need to adjust the other
        if zeros1 == 0:
            # We can only increase sum2 by at least 1 per zero
            # So sum2 needs to be at least sum2 + zeros2
            if sum2 + zeros2 > sum1:
                return -1
            else:
                return sum1
        elif zeros2 == 0:
            # Similarly for sum1
            if sum1 + zeros1 > sum2:
                return -1
            else:
                return sum2

        # Both arrays have zeros
        # We can increase both sums by at least 1 per zero
        # So we need to find the minimum sum where both can be adjusted to match
        # The minimum possible sum is max(sum1 + zeros1, sum2 + zeros2)
        # Because each zero can be replaced by at least 1
        return max(sum1 + zeros1, sum2 + zeros2)
