class Solution:
    def numTilings(self, n: int) -> int:
        MOD = 10**9 + 7
        if n == 0:
            return 0
        if n == 1:
            return 1

        dp = [[0] * (n + 1) for _ in range(3)]

        dp[0][0] = 1  # No tiles, no space
        dp[1][0] = 0  # One tile on top, no space
        dp[2][0] = 0  # One tile on bottom, no space

        for i in range(1, n + 1):
            # dp[0][i] = number of ways to fill 2x i board completely
            # dp[1][i] = number of ways to fill 2x i board with one extra square on top
            # dp[2][i] = number of ways to fill 2x i board with one extra square on bottom

            # Transition for dp[0][i]
            dp[0][i] = (dp[0][i-1] + dp[1][i-1] + dp[2][i-1]) % MOD

            # Transition for dp[1][i]
            if i >= 1:
                dp[1][i] = (dp[0][i-1] + dp[1][i-1]) % MOD
            if i >= 2:
                dp[1][i] = (dp[1][i] + dp[2][i-2]) % MOD

            # Transition for dp[2][i]
            if i >= 1:
                dp[2][i] = (dp[0][i-1] + dp[2][i-1]) % MOD
            if i >= 2:
                dp[2][i] = (dp[2][i] + dp[1][i-2]) % MOD

        return dp[0][n] % MOD
