class Solution:
    def maxArrayValue(self, nums: List[int]) -> int:
        # Start from the end of the array and work backwards
        max_value = nums[-1]
        current_sum = nums[-1]

        for i in range(len(nums) - 2, -1, -1):
            if nums[i] <= current_sum:
                current_sum += nums[i]
            else:
                current_sum = nums[i]
            max_value = max(max_value, current_sum)

        return max_value
