class Solution:
    def circularArrayLoop(self, nums: List[int]) -> bool:
        n = len(nums)
        for i in range(n):
            if nums[i] == 0:
                continue
            # Mark visited elements to avoid cycles
            visited = [False] * n
            slow, fast = i, i
            direction = nums[i]
            found_cycle = False
            while True:
                # Move slow
                slow = (slow + nums[slow]) % n
                if nums[slow] * direction < 0:
                    break
                if visited[slow]:
                    if slow == i:
                        found_cycle = True
                    break
                visited[slow] = True
                # Move fast
                fast = (fast + nums[fast]) % n
                if nums[fast] * direction < 0:
                    break
                if visited[fast]:
                    if fast == i:
                        found_cycle = True
                    break
                visited[fast] = True
                fast = (fast + nums[fast]) % n
                if nums[fast] * direction < 0:
                    break
                if visited[fast]:
                    if fast == i:
                        found_cycle = True
                    break
                visited[fast] = True
            if found_cycle:
                return True
            # Mark visited elements as 0 to avoid reprocessing
            for j in range(n):
                if visited[j]:
                    nums[j] = 0
        return False
