from typing import List
from collections import defaultdict
import heapq

class Solution:
    def numberOfSets(self, n: int, maxDistance: int, roads: List[List[int]]) -> int:
        def dijkstra(start, graph):
            dist = [float('inf')] * n
            dist[start] = 0
            heap = [(0, start)]
            while heap:
                d, u = heapq.heappop(heap)
                if d > dist[u]:
                    continue
                for v, w in graph[u]:
                    if dist[v] > d + w:
                        dist[v] = d + w
                        heapq.heappush(heap, (dist[v], v))
            return dist

        # Build the graph
        graph = defaultdict(list)
        for u, v, w in roads:
            graph[u].append((v, w))
            graph[v].append((u, w))

        # Try all subsets of nodes to keep
        result = 0
        from itertools import combinations

        for k in range(n + 1):
            for subset in combinations(range(n), k):
                # Build subgraph
                subgraph = defaultdict(list)
                for u in subset:
                    for v, w in graph[u]:
                        if v in subset:
                            subgraph[u].append((v, w))

                # Check if all pairs in subset are within maxDistance
                valid = True
                for i in subset:
                    dist = dijkstra(i, subgraph)
                    for j in subset:
                        if dist[j] > maxDistance:
                            valid = False
                            break
                    if not valid:
                        break
                if valid:
                    result += 1

        return result

def run_tests():
