class Solution:
    def matchReplacement(self, s: str, sub: str, mappings: List[List[str]]) -> bool:
        # Create a dictionary to store allowed replacements
        allowed_replacements = {}
        for old, new in mappings:
            if old not in allowed_replacements:
                allowed_replacements[old] = []
            allowed_replacements[old].append(new)

        # Check each possible starting position in s
        for i in range(len(s) - len(sub) + 1):
            match = True
            for j in range(len(sub)):
                s_char = s[i + j]
                sub_char = sub[j]
                if s_char != sub_char:
                    # Check if we can replace sub_char with s_char
                    if sub_char not in allowed_replacements or s_char not in allowed_replacements[sub_char]:
                        match = False
                        break
            if match:
