class Solution:
    def makeSubKSumEqual(self, arr: List[int], k: int) -> int:
        n = len(arr)
        k = k % n
        groups = []
        for i in range(k):
            group = []
            for j in range(i, n, k):
                group.append(arr[j])
            groups.append(group)

        result = 0
        for group in groups:
            median = sorted(group)[len(group) // 2]
            for num in group:
                result += abs(num - median)
        return result

