class Solution:
    def getLengthOfOptimalCompression(self, s: str, k: int) -> int:
        from functools import lru_cache

        n = len(s)

        @lru_cache(None)
        def dp(i, j, k_left, prev_char, count):
            if i == n:
                return len(str(count)) if count > 0 else 0
            if k_left < 0:
                return float('inf')

            # Option 1: delete the current character
            delete = dp(i + 1, j, k_left - 1, prev_char, count)

            # Option 2: keep the current character
            if s[i] == prev_char:
                keep = dp(i + 1, j, k_left, prev_char, count + 1)
            else:
                keep = dp(i + 1, j, k_left, s[i], count + 1) + 1

            return min(delete, keep)

        return dp(0, 0, k, '', 0)
