class Solution:
    def findSubstringInWraproundString(self, s: str) -> int:
        # Dictionary to store the maximum length of consecutive sequence ending at each character
        max_len = {}
        current_len = 0

        for i in range(len(s)):
            # Check if current character is part of a consecutive sequence
            if i == 0 or (ord(s[i]) - ord(s[i-1]) == 1 and s[i] != s[i-1]):
                current_len += 1
            else:
                current_len = 1

            # Update the maximum length for the current character
            char = s[i]
            if char not in max_len or current_len > max_len[char]:
                max_len[char] = current_len

        # Sum up the maximum lengths for each character
        return sum(max_len.values())
