class Solution:
    def removeStones(self, stones: List[List[int]]) -> int:
        from collections import defaultdict

        # We can model this as a graph problem where each stone is a node.
        # Two stones are connected if they share the same row or column.
        # The problem reduces to finding the number of connected components in this graph.
        # The maximum number of stones that can be removed is total stones - number of connected components.

        # We'll use Union-Find (Disjoint Set Union) to find connected components.

        parent = {}

        def find(x):
            if parent[x] != x:
                parent[x] = find(parent[x])
            return parent[x]

        def union(x, y):
            root_x = find(x)
            root_y = find(y)
            if root_x != root_y:
                parent[root_x] = root_y

        # Map each stone to a unique identifier to avoid conflicts between row and column keys
        # We can use a tuple (x, y) as the key for the stones, and for rows and columns, we can use (x, -1) and (-1, y) respectively.

        # First, create a unique identifier for each stone
        for x, y in stones:
            parent[(x, y)] = (x, y)

        # Now, connect stones that share the same row or column
        for x, y in stones:
            # Connect with all other stones in the same row
            for other_x, other_y in stones:
                if other_x == x and (other_x, other_y) != (x, y):
                    union((x, y), (other_x, other_y))
            # Connect with all other stones in the same column
            for other_x, other_y in stones:
                if other_y == y and (other_x, other_y) != (x, y):
                    union((x, y), (other_x, other_y))

        # Count the number of unique roots (connected components)
        unique_roots = set()
        for x, y in stones:
            unique_roots.add(find((x, y)))

        # The maximum number of stones that can be removed is total stones - number of connected components
        return len(stones) - len(unique_roots)
