class Solution:
    def incremovableSubarrayCount(self, nums: List[int]) -> int:
        n = len(nums)
        if n == 0:
            return 0

        # Precompute the strictly increasing prefix
        prefix = []
        for i in range(n):
            if not prefix or nums[i] > prefix[-1]:
                prefix.append(nums[i])

        # Precompute the strictly increasing suffix
        suffix = []
        for i in range(n - 1, -1, -1):
            if not suffix or nums[i] > suffix[-1]:
                suffix.append(nums[i])
        suffix = suffix[::-1]

        result = 0

        for i in range(n):
            for j in range(i, n):
                # Check if removing nums[i..j] makes the remaining array strictly increasing
                left = nums[:i]
                right = nums[j+1:]
                if not left and not right:
                    result += 1
                    continue
                if not left:
                    if is_increasing(right):
                        result += 1
                        continue
                if not right:
                    if is_increasing(left):
