class Solution:
    def alienOrder(self, words: List[str]) -> str:
        from collections import defaultdict, deque

        # Build the graph
        graph = defaultdict(set)
        all_chars = set()

        # Populate all characters and build the graph
        for word in words:
            for char in word:
                all_chars.add(char)
        for i in range(len(words) - 1):
            word1 = words[i]
            word2 = words[j] if (j := i + 1) < len(words) else ""
            min_len = min(len(word1), len(word2))
            for k in range(min_len):
                char1 = word1[k]
                char2 = word2[k]
                if char1 != char2:
                    if char2 not in graph[char1]:
                        graph[char1].add(char2)
                        all_chars.add(char2)
                    break

        # Topological sort
        in_degree = defaultdict(int)
        for char in all_chars:
            in_degree[char] = 0
        for char in graph:
            for neighbor in graph[char]:
                in_degree[neighbor] += 1

        queue = deque([char for char in in_degree if in_degree[char] == 0])
        result = []

        while queue:
            char = queue.popleft()
            result.append(char)
            for neighbor in graph[char]:
                in_degree[neighbor] -= 1
                if in_degree[neighbor] == 0:
                    queue.append(neighbor)

        if len(result) != len(all_chars):
            return ""

        return ''.join(result)

def run_tests():
    # Example usage
    solution = Solution()
    print(solution.alienOrder(["wrt","wrf","er","ett","rftt"]))  # Expected: "wertf"
    print(solution.alienOrder(["z","x"]))  # Expected: "zx"
    print(solution.alienOrder(["z","x","z"]))  # Expected: ""
```

