from typing import List

class Solution:
    def maxXor(self, n: int, edges: List[List[int]], values: List[int]) -> int:
        # Build the tree as an adjacency list
        tree = [[] for _ in range(n)]
        for u, v in edges:
            tree[u].append(v)
            tree[v].append(u)

        max_score = 0

        # Helper function to calculate subtree sum and track all possible subtree sums
        def dfs(node: int, parent: int) -> List[int]:
            subtree_sum = values[node]
            for neighbor in tree[node]:
                if neighbor != parent:
                    subtree_sum += dfs(neighbor, node)
            # Include the current node's value and all its descendants
            # We'll track all possible subtree sums from this node
            current_subtree_sums = [subtree_sum]
            for neighbor in tree[node]:
                if neighbor != parent:
                    current_subtree_sums.extend(dfs(neighbor, node))
            return current_subtree_sums

        # Collect all subtree sums
        all_subtree_sums = dfs(0, -1)

        # Find the maximum XOR of any two distinct elements
        max_xor = 0
        for i in range(len(all_subtree_sums)):
            for j in range(i + 1, len(all_subtree_sums)):
                current_xor = all_subtree_sums[i] ^ all_subtree_sums[j]
                if current_xor > max_xor:
                    max_xor = current_xor
        return max_xor
