from typing import List

class Solution:
    def ambiguousCoordinates(self, s: str) -> List[str]:
        # Helper function to generate valid numbers from a string
        def generate_numbers(string: str) -> List[str]:
            n = len(string)
            result = []
            # Skip leading zeros
            if string[0] == '0':
                if n == 1:
                    result.append(string)
                else:
                    # Check for leading zero with more digits
                    if string[1] != '0':
                        result.append("0." + string[1:])
                    else:
                        # Avoid "00", "000", etc.
                        pass
            else:
                # Check for integer
                result.append(string)
                # Check for decimal
                for i in range(1, n):
                    if string[i] == '0':
                        continue  # Avoid leading zero after decimal
                    result.append(string[:i] + "." + string[i:])
            return result

        # Remove the parentheses
        s = s[1:-1]
        n = len(s)
        result = []

        # Try all possible splits
        for i in range(1, n):
            left = s[:i]
            right = s[i:]

            # Generate valid numbers for left and right parts
            left_numbers = generate_numbers(left)
            right_numbers = generate_numbers(right)

            # Combine valid numbers
            for l in left_numbers:
                for r in right_numbers:
                    result.append(f"({l}, {r})")

        return result

