        color_positions = defaultdict(set)
        color_min_row = {}
        color_max_row = {}
        color_min_col = {}
        color_max_col = {}

        # Collect positions and boundaries for each color
        for i in range(m):
            for j in range(n):
                color = targetGrid[i][j]
                color_positions[color].add((i, j))
                color_min_row[color] = min(color_min_row.get(color, m), i)
                color_max_row[color] = max(color_max_row.get(color, -1), i)
                color_min_col[color] = min(color_min_col.get(color, n), j)
                color_max_col[color] = max(color_max_col.get(color, -1), j)

        # Build graph: color -> list of colors that must come after it
        color_graph = defaultdict(set)
        color_set = set(color_positions.keys())
        for color in color_set:
            for i in range(color_min_row[color], color_max_row[color] + 1):
                for j in range(color_min_col[color], color_max_col[color] + 1):
                    target_color = targetGrid[i][j]
                    if target_color != color:
                        color_graph[color].add(target_color)

        # Check for cycles using topological sort
        in_degree = {color: 0 for color in color_set}
        for color in color_graph:
            for neighbor in color_graph[color]:
                in_degree[neighbor] += 1

        queue = deque([color for color in color_set if in_degree[color] == 0])
        visited = set()

        while queue:
            current = queue.popleft()
            visited.add(current)
            for neighbor in color_graph[current]:
                in_degree[neighbor] -= 1
                if in_degree[neighbor] == 0:
                    queue.append(neighbor)

        return len(visited) == len(color_set)

