class Solution:
    def largestDivisibleSubset(self, nums: List[int]) -> List[int]:
        if not nums:
            return []

        nums.sort()
        n = len(nums)
        dp = [1] * n  # dp[i] will store the size of the largest divisible subset ending at index i
        parent = [-1] * n  # To reconstruct the subset

        max_len = 1
        index = 0

        for i in range(n):
            for j in range(i):
                if nums[i] % nums[j] == 0:
                    if dp[j] + 1 > dp[i]:
                        dp[i] = dp[j] + 1
                        parent[i] = j
            if dp[i] > max_len:
                max_len = dp[i]
                index = i

        # Reconstruct the subset
        result = []
        while index != -1:
            result.append(nums[index])
            index = parent[index]

        return result[::-1]
