class Solution:
    def widestPairOfIndices(self, nums1: List[int], nums2: List[int]) -> int:
        n = len(nums1)
        prefix1 = [0] * (n + 1)
        prefix2 = [0] * (n + 1)

        for i in range(n):
            prefix1[i + 1] = prefix1[i] + nums1[i]
            prefix2[i + 1] = prefix2[i] + nums2[i]

        max_len = 0
        diff_map = {}

        for i in range(n + 1):
            diff = prefix1[i] - prefix2[i]
            if diff in diff_map:
                max_len = max(max_len, i - diff_map[diff])
            else:
                diff_map[diff] = i

        return max_len
