from typing import List

class Solution:
    def shortestSubstrings(self, arr: List[str]) -> List[str]:
        n = len(arr)
        # Create a set to store all substrings from all strings except the current one
        all_substrings = [set() for _ in range(n)]

        # Populate the set of substrings for each string
        for i in range(n):
            for j in range(len(arr[i])):
                for k in range(j + 1, len(arr[i]) + 1):
                    substr = arr[i][j:k]
                    for l in range(n):
                        if l != i:
                            all_substrings[l].add(substr)

        answer = []
        for i in range(n):
            min_length = len(arr[i]) + 1  # Initialize with a value larger than any possible substring length
            result = ""
            for j in range(len(arr[i])):
                for k in range(j + 1, len(arr[i]) + 1):
                    substr = arr[i][j:k]
                    if substr not in all_substrings[i] and len(substr) < min_length:
                        min_length = len(substr)
                        result = substr
                    elif substr not in all_substrings[i] and len(substr) == min_length:
                        if substr < result:
                            result = substr
            answer.append(result if min_length <= len(arr[i]) else "")
        return answer

def run_tests():
