class Solution:
    def numDistinct(self, s: str, t: str) -> int:
        m, n = len(s), len(t)
        # Create a 2D DP table where dp[i][j] represents the number of distinct subsequences of s[:i] that equal t[:j]
        dp = [[0] * (n + 1) for _ in range(m + 1)]

        # Base case: empty t can be formed in 1 way from any s
        for i in range(m + 1):
            dp[i][0] = 1

        for i in range(1, m + 1):
            for j in range(1, n + 1):
                if s[i - 1] == t[j - 1]:
                    # If characters match, add the number of ways from s[:i-1] and t[:j-1]
                    dp[i][j] = dp[i - 1][j - 1] + dp[i - 1][j]
                else:
                    # If characters do not match, carry over the number of ways from s[:i-1]
                    dp[i][j] = dp[i - 1][j]

        return dp[m][n]

def run_tests():
    solution = Solution()
    assert solution.numDistinct("rabbbit", "rabbit") == 3
    assert solution.numDistinct("babgbag", "bag") == 5
    print("All test cases passed.")

