class Solution:
    def atMostNGivenDigitSet(self, digits: List[str], n: int) -> int:
        s = str(n)
        length = len(s)
        count = 0
        # Count numbers with less digits than n
        for i in range(1, length):
            count += len(digits) ** i
        # Count numbers with same number of digits as n
        i = 0
        while i < length:
            # Check if current digit in n is greater than any digit in digits
            found = False
            for d in digits:
                if d < s[i]:
                    count += 1
                elif d == s[i]:
                    found = True
                    break
            if not found:
                break
            i += 1
        return count
