from typing import List

class Solution:
    def longestIncreasingPath(self, matrix: List[List[int]]) -> int:
        if not matrix:
            return 0
        m, n = len(matrix), len(matrix[0])
        dp = [[1]*n for _ in range(m)]
        directions = [(-1,0),(1,0),(0,-1),(0,1)]

        def dfs(i, j):
            max_len = 1
            for dx, dy in directions:
                x, y = i + dx, j + dy
                if 0 <= x < m and 0 <= y < n and matrix[x][y] > matrix[i][j]:
                    if dp[x][y] < 1 + dfs(x, y):
                        dp[i][j] = 1 + dfs(x, y)
                    max_len = max(max_len, dp[i][j])
            return max_len

        for i in range(m):
            for j in range(n):
                dfs(i, j)

        return max(max(row) for row in dp)

def run_tests():
    # Example 1
    matrix1 = [[9,9,4],[6,6,8],[2,1,1]]
    sol = Solution()
    print(sol.longestIncreasingPath(matrix1))  # Output: 4

    # Example 2
    matrix2 = [[3,4,5],[3,2,6],[2,2,1]]
    print(sol.longestIncreasingPath(matrix2))  # Output: 4

    # Example 3
    matrix3 = [[1]]
    print(sol.longestIncreasingPath(matrix3))  # Output: 1
