class Solution:
    def palindromePairs(self, words: List[str]) -> List[List[int]]:
        word_to_index = {word: i for i, word in enumerate(words)}
        result = []

        for i, word in enumerate(words):
            for j in range(len(word) + 1):
                prefix = word[:j]
                suffix = word[j:]
                # Case 1: word[i] + word[j] is a palindrome
                # Check if suffix is a palindrome and if prefix exists in the map
                if j < len(word) and suffix == suffix[::-1] and prefix in word_to_index:
                    if word_to_index[prefix] != i:
                        result.append([i, word_to_index[prefix]])
                # Case 2: word[j] + word[i] is a palindrome
                # Check if prefix is a palindrome and if suffix exists in the map
                if j > 0 and prefix == prefix[::-1] and suffix in word_to_index:
                    if word_to_index[suffix] != i:
                        result.append([word_to_index[suffix], i])

        return result
