from typing import List

class Solution:
    def minOperations(self, nums: List[int]) -> int:
        operations = 0
        current_flips = 0

        for i in range(len(nums) - 1, -1, -1):
            # Determine the desired value at this position
            desired = 1 if i == len(nums) - 1 else nums[i + 1]

            # If the current value doesn't match the desired value
            if nums[i] != desired:
                operations += 1
                current_flips += 1
            else:
                # If we have an odd number of flips, it will flip the current value
                if current_flips % 2 == 1:
                    nums[i] ^= 1  # Flip the value
        return operations
